// components/HeaderSide.tsx
import React from "react";

interface HeaderSideProps {
  showCertificates: boolean;
  setShowCertificates: (show: boolean) => void;
}

export default function HeaderSide({ showCertificates, setShowCertificates }: HeaderSideProps) {
  return (
    <section className="header">
      <img 
        className="header-img" 
        src="https://i.ibb.co/kBnt5xh/perfil.jpg" 
        alt="Luis Tito Salinas Garcia"
      />
      <h1>Luis Tito <br /> Salinas Garcia</h1>
      <h2>FullStack Developer</h2>
      
      <div className="socials">
        <a href="https://www.youtube.com/@luistitosalinasgarcia" target="_blank" rel="noopener noreferrer" className="fab fa-youtube" id="profile-link"></a>
        <a href="https://www.facebook.com/luistitosalinasgarciabusiness" target="_blank" rel="noopener noreferrer" className="fab fa-facebook"></a>
        <a href="https://www.tiktok.com/@luistitosalinasgarciabusiness" target="_blank" rel="noopener noreferrer" className="fab fa-tiktok"></a>
      </div>

      {showCertificates ? (
        <button 
          onClick={() => setShowCertificates(false)} 
          className="cta" 
          style={{ border: "none", cursor: "pointer" }}
        >
          <i className="fas fa-arrow-left" style={{ marginRight: "8px" }}></i> 
          Back to Portfolio
        </button>
      ) : (
        <button 
          onClick={() => setShowCertificates(true)} 
          className="cta" 
          style={{ border: "none", cursor: "pointer" }}
        >
          My Certificates
        </button>
      )}
    </section>
  );
}