// components/Menu.tsx
import React from "react";

interface MenuProps {
  onMenuClick: () => void;
}

export default function Menu({ onMenuClick }: MenuProps) {
  return (
    <div className="menu">
      <a 
        href="#welcome-section" 
        className="menu-icon fas fa-home"
        onClick={onMenuClick}
      ></a>
      <a 
        href="#about" 
        className="menu-icon fas fa-user"
        onClick={onMenuClick}
      ></a>
      <a 
        href="#projects" 
        className="menu-icon fas fa-code"
        onClick={onMenuClick}
      ></a>
      <a 
        href="#experience" 
        className="menu-icon fas fa-briefcase"
        onClick={onMenuClick}
      ></a>
      <a 
        href="#contact" 
        className="menu-icon fas fa-envelope"
        onClick={onMenuClick}
      ></a>
    </div>
  );
}