// components/sections/ProjectsSection.tsx
import React from "react";

const projects = [
  {
    id: 1,
    title: "Mikhuna SaaS",
    issuer: "Mikhuna SaaS",
    image: "/mikhunasaas.png",
    link: "https://mikhunasaas.com"
  },
  {
    id: 2,
    title: "STPOS",
    issuer: "STPOS",
    image: "/stpos.png",
    link: "https://stpos.salinastech.com" 
  }
];

export default function ProjectsSection() {
  return (
    <section className="content-card projects" id="projects">
      <h1>Projects</h1>
      <div className="col-2 project-list">
        {projects.map((project) => (
          <a 
            key={project.id} 
            href={project.link} 
            target="_blank" 
            rel="noopener noreferrer" 
            className="project-tile project-link"
          >
            <img src={project.image} alt={project.title} />
            <div className="overlay">
              <div className="project-description">
                <h3>{project.title}</h3>
                <p></p>
              </div>
            </div>
          </a>
        ))}
      </div>
      <a href="https://github.com/LuisTitoSalinasGarcia" target="_blank" rel="noopener noreferrer">see more...</a>
    </section>
  );
}