// components/sections/ContactSection.tsx
"use client";
import React from "react";

export default function ContactSection() {
  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    
    const formData = new FormData(e.currentTarget);
    const name = formData.get("name") as string;
    const email = formData.get("email") as string;
    const subject = formData.get("subject") as string;
    const message = formData.get("text") as string;

    // Validación básica preventiva
    if (!name || !email || !message) {
      alert("Por favor, completa los campos requeridos (Nombre, Email y Mensaje).");
      return;
    }

    const phoneNumber = "59164846140"; 
    
    const formattedText = `*NUEVO MENSAJE*\n\n` +
                          `*Nombre:* ${name}\n` +
                          `*Email:* ${email}\n` +
                          `*Asunto:* ${subject || 'Sin asunto'}\n\n` +
                          `*Mensaje:*\n${message}`;

    const whatsappUrl = `https://api.whatsapp.com/send?phone=${phoneNumber}&text=${encodeURIComponent(formattedText)}`;
    
    window.open(whatsappUrl, "_blank", "noopener,noreferrer");
  };

  return (
    <section className="content-card contact" id="contact">
      <h1>Contact</h1>
      <form className="form" id="form" onSubmit={handleSubmit}>
        <div className="input-box">
          <input type="text" className="text-input" name="name" placeholder="Name" required />
        </div>
        <div className="input-box">
          <input type="email" className="text-input" name="email" id="email" placeholder="Email" required />
        </div>
        <div className="input-box">
          <input type="text" className="text-input" name="subject" id="subject" placeholder="Subject" />
        </div>
        <div className="input-box">
          <textarea name="text" className="message" placeholder="Message..." required></textarea>
        </div>
        <div className="input-box submit-box">
          <input type="submit" className="submit-btn" id="submit" value="Send Message" />
        </div>
      </form>
    </section>
  );
}